    <div class="container">
        <div class="header">
            <h1>📝 Todo App</h1>
            <p>Manage your tasks with React & Flask</p>
        </div>
        <div class="form">
            <input 
                type="text" 
                id="todoInput" 
                class="form-input" 
                placeholder="What needs to be done?"
                onkeypress="if(event.key === 'Enter') addTodo()"
            >
            <button id="addButton" class="form-button" onclick="addTodo()">Add Todo</button>
        </div>
        <div id="loading" class="loading"></div>
        <ul id="todoList" class="todo-list"></ul>
    </div>

    <script>
        // API Configuration
        const API_URL = 'http://localhost:5000/api/todos';

        // State
        let todos = [];
        let editingId = null;

        // Load todos on page load
        document.addEventListener('DOMContentLoaded', () => {
            fetchTodos();
        });

        // Fetch all todos
        async function fetchTodos() {
            try {
                const response = await fetch(API_URL);
                if (!response.ok) throw new Error('Failed to fetch todos');
                todos = await response.json();
                renderTodos();
            } catch (error) {
                console.error('Error fetching todos:', error);
                showNotification('Failed to load todos', 'error');
                renderTodos();
            }
        }

        // Add new todo
        async function addTodo() {
            const input = document.getElementById('todoInput');
            const text = input.value.trim();

            if (!text) {
                showNotification('Please enter a todo', 'error');
                return;
            }

            try {
                const response = await fetch(API_URL, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ text, completed: false }),
                });

                if (!response.ok) throw new Error('Failed to add todo');

                const newTodo = await response.json();
                todos.push(newTodo);
                input.value = '';
                renderTodos();
                showNotification('Todo added successfully!', 'success');
            } catch (error) {
                console.error('Error adding todo:', error);
                showNotification('Failed to add todo', 'error');
            }
        }

        // Toggle todo completion
        async function toggleTodo(id) {
            const todo = todos.find(t => t.id === id);
            if (!todo) return;

            try {
                const response = await fetch(`${API_URL}/${id}`, {
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ ...todo, completed: !todo.completed }),
                });

                if (!response.ok) throw new Error('Failed to update todo');

                todo.completed = !todo.completed;
                renderTodos();
            } catch (error) {
                console.error('Error toggling todo:', error);
                showNotification('Failed to update todo', 'error');
            }
        }

        // Delete todo
        async function deleteTodo(id) {
            if (!confirm('Are you sure you want to delete this todo?')) return;

            try {
                const response = await fetch(`${API_URL}/${id}`, {
                    method: 'DELETE',
                });

                if (!response.ok) throw new Error('Failed to delete todo');

                todos = todos.filter(t => t.id !== id);
                renderTodos();
                showNotification('Todo deleted', 'success');
            } catch (error) {
                console.error('Error deleting todo:', error);
                showNotification('Failed to delete todo', 'error');
            }
        }

        // Start editing todo
        function startEdit(id) {
            editingId = id;
            renderTodos();
        }

        // Save edited todo
        async function saveEdit(id, newText) {
            const todo = todos.find(t => t.id === id);
            if (!todo || !newText.trim()) return;

            try {
                const response = await fetch(`${API_URL}/${id}`, {
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ ...todo, text: newText.trim() }),
                });

                if (!response.ok) throw new Error('Failed to update todo');

                todo.text = newText.trim();
                editingId = null;
                renderTodos();
                showNotification('Todo updated', 'success');
            } catch (error) {
                console.error('Error updating todo:', error);
                showNotification('Failed to update todo', 'error');
            }
        }

        // Cancel editing
        function cancelEdit() {
            editingId = null;
            renderTodos();
        }

        // Render todos
        function renderTodos() {
            const list = document.getElementById('todoList');
            const loading = document.getElementById('loading');

            if (todos.length === 0) {
                list.innerHTML = `
                    <li class="empty-state">
                        <svg fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4"></path>
                        </svg>
                        <p>No todos yet. Add one above!</p>
                    </li>
                `;
                loading.style.display = 'none';
                return;
            }

            loading.style.display = 'none';
            list.innerHTML = todos.map(todo => {
                if (editingId === todo.id) {
                    return `
                        <li class="todo-item">
                            <input 
                                type="text" 
                                class="edit-input" 
                                id="edit-input-${todo.id}"
                                value="${todo.text}"
                                onkeypress="if(event.key === 'Enter') saveEdit(${todo.id}, this.value)"
                            >
                            <button class="save-button" onclick="saveEdit(${todo.id}, document.getElementById('edit-input-${todo.id}').value)">Save</button>
                            <button class="action-button edit-button" onclick="cancelEdit()">Cancel</button>
                        </li>
                    `;
                }

                return `
                    <li class="todo-item ${todo.completed ? 'completed' : ''}">
                        <input 
                            type="checkbox" 
                            class="todo-checkbox" 
                            ${todo.completed ? 'checked' : ''} 
                            onchange="toggleTodo(${todo.id})"
                        >
                        <span class="todo-text">${escapeHtml(todo.text)}</span>
                        <div class="todo-actions">
                            <button class="action-button edit-button" onclick="startEdit(${todo.id})">Edit</button>
                            <button class="action-button delete-button" onclick="deleteTodo(${todo.id})">Delete</button>
                        </div>
                    </li>
                `;
            }).join('');
        }

        // Escape HTML to prevent XSS
        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        // Show notification
        function showNotification(message, type) {
            const notification = document.createElement('div');
            notification.className = `notification ${type}`;
            notification.textContent = message;
            document.body.appendChild(notification);

            setTimeout(() => {
                notification.classList.add('fadeOut');
                notification.addEventListener('animationend', () => {
